import (
	"fmt"
	"html"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get the keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Build the HTML response
	htmlResponse := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Search Results: %s</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword, escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlResponse)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)
	fmt.Println("Server starting on :8080...")
	http.ListenAndServe(":8080", nil)
}

